// Accept input from the webhook (fields under body) or the manual test (direct fields)
const src = $json.body ?? $json;
return [{
  json: {
    requested_by: src.requested_by ?? 'unknown',
    service_needed: src.service_needed ?? '',
    budget_ceiling: src.budget_ceiling ?? '',
    deadline: src.deadline ?? '',
    notes: src.notes ?? ''
  }
}];

// Condensed system prompt. The full authoritative version lives in
// bp-specialized-team/prompts/ahmed-procurement.md — keep the two in sync.
const intake = $('Normalize Input').first().json;

const suppliers = $input.all()
  .map(i => i.json)
  .filter(j => j && (j.name || j.properties))
  .slice(0, 50);
const suppliersText = suppliers.length
  ? JSON.stringify(suppliers)
  : 'SUPPLIERS_DB_UNAVAILABLE — note that no existing supplier data was found; propose the sourcing criteria instead of naming suppliers.';

const systemPrompt = [
  'You are Ahmed, the internal Procurement Agent for Business Partner (بزنس بارتنر سلوشنز).',
  'You serve the internal team (mainly Badr in Sales). You never talk to company clients.',
  'Rules:',
  '- Reply in Arabic, structured and brief.',
  '- Prefer existing approved suppliers from the database before proposing new ones.',
  '- Shortlist up to 3 options with a comparison (السعر / النطاق / الشروط / الجاهزية).',
  '- Never commit, accept, pay, or promise anything to a supplier.',
  '- Never invent supplier prices — if a price is not in the data, mark it "يحتاج عرض سعر".',
  '- Never include client data or internal pricing strategy in supplier-facing text.',
  '- Any supplier-facing message is a DRAFT pending approval — never written as sent.',
  'If a supplier outreach draft is warranted, include it in your reply and end the reply with the exact marker [OUTREACH_READY] on its own line.',
  '',
  'Suppliers database (JSON):',
  suppliersText
].join('\n');

const userContent = [
  `Requested by: ${intake.requested_by}`,
  `Service needed: ${intake.service_needed}`,
  `Budget ceiling: ${intake.budget_ceiling || 'not set'}`,
  `Deadline: ${intake.deadline || 'not set'}`,
  `Notes: ${intake.notes || 'none'}`
].join('\n');

return [{
  json: {
    anthropic_body: {
      model: 'claude-sonnet-5',
      max_tokens: 1500,
      system: systemPrompt,
      messages: [{ role: 'user', content: userContent }]
    }
  }
}];

// Resilience (Compliance Agent V1 pattern): if the engine fails, use a safe fallback
// reply and keep the flow alive.
const item = $input.first().json;
const fallback = 'تم استلام طلب التوريد وسيتم تجهيز المقارنة والمسودة. (تعذر توليد Claude حالياً — الطلب مسجل وسيراجعه الفريق يدوياً.)';

let text = '';
if (item && Array.isArray(item.content) && item.content[0] && item.content[0].text) {
  text = item.content[0].text;
}
const engine_fallback = !text;
if (engine_fallback) text = fallback;

const outreach_ready = !engine_fallback && text.includes('[OUTREACH_READY]');
const reply = text.replace('[OUTREACH_READY]', '').trim();

const intake = $('Normalize Input').first().json;
return [{ json: { ...intake, reply, outreach_ready, engine_fallback } }];
